detection_pack.kql:
// ================================================================
// KQL — Microsoft Sentinel / Defender XDR
// APEX Advisory: CVE-2026-9453 - FoundDream miniclawd SkillsLoader skills-loa
// CVE: CVE-2026-9453 | Class: COMMAND_INJECTION | APEX v161.0
// Generated: 2026-05-25
// ================================================================

let lookback = 30d;

// IOC-based hunt — network events
let apex_iocs = dynamic(["2d65665046e2222eeea76cafc8570ed546a8c125", "https://cvefeed.io/vuln/detail/CVE-2026-9453", "cstecgi.cgi", "requires.bins", "skills-loader.ts"]);
DeviceNetworkEvents
| where Timestamp > ago(lookback)
| where RemoteUrl has_any (apex_iocs) or RemoteIP has_any (apex_iocs)
| extend Severity = "High", Rule = "APEX-CVE-2026-9453-IOC"
| project Timestamp, DeviceName, RemoteUrl, RemoteIP, InitiatingProcessFileName, Severity, Rule
| order by Timestamp desc;


// Alert rule: SecurityAlert table correlation
SecurityAlert
| where TimeGenerated > ago(lookback)
| where AlertName contains "CVE-2026-9453" or Description contains "CVE-2026-9453"
| extend Rule = "APEX-CVE-2026-9453-ALERT"
| project TimeGenerated, AlertName, AlertSeverity, Entities, Description, Rule
| order by TimeGenerated desc;

