sigma.retro_hunt_query:
// RETRO-HUNT: intel--11f3d939c15d69eba10ccb5a | Techniques: T1190, T1059 | Lookback: 90d
// Generated by APEX Detection Validation Engine v162.0.0
let lookback = 90d;
let indicators = dynamic(["<indicator>"]);
union DeviceProcessEvents, DeviceNetworkEvents, DeviceFileEvents
| where TimeGenerated > ago(lookback)
| where ProcessCommandLine has_any (indicators)
    or RemoteUrl has_any (indicators)
    or FileName has_any (indicators)
| summarize HuntHits=count(), FirstSeen=min(TimeGenerated),
